// Extraer identificadores del payload de Meta
const body = $input.first().json;
const object = body.object;
const entries = body.entry || [];

let normalized = {
  raw: body,
  object_type: object,
  source_ids: [],
  event_type: 'unknown',
  brand_id: null
};

for (const entry of entries) {
  if (entry.id) normalized.source_ids.push(entry.id);
  // Detectar tipo de evento
  if (entry.messaging) normalized.event_type = object === 'instagram' ? 'instagram_dm' : 'facebook_message';
  if (entry.changes) {
    const field = entry.changes[0]?.field;
    if (field === 'comments') normalized.event_type = 'instagram_comment';
    if (field === 'messages' && entry.changes[0]?.value?.messaging_product === 'whatsapp') {
      normalized.event_type = 'whatsapp_message';
      const phoneId = entry.changes[0]?.value?.metadata?.phone_number_id;
      if (phoneId) normalized.source_ids.push('phone:' + phoneId);
    }
  }
}

return normalized;

// Mapa de IDs a brand_id (completar con valores reales del .env)
const BRAND_MAP = {
  [process.env.KMEDIA_FACEBOOK_PAGE_ID]: 'kmediafilms',
  [process.env.KMEDIA_IG_BUSINESS_ID]: 'kmediafilms',
  [process.env.ANA_FACEBOOK_PAGE_ID]: 'ana',
  [process.env.ANA_IG_BUSINESS_ID]: 'ana',
  ['phone:' + process.env.ANA_PHONE_NUMBER_ID]: 'ana',
  [process.env.DRIVIP_FACEBOOK_PAGE_ID]: 'drivip',
  [process.env.DRIVIP_IG_BUSINESS_ID]: 'drivip',
  ['phone:' + process.env.DRIVIP_PHONE_NUMBER_ID]: 'drivip',
};

const data = $input.first().json;
let brand_id = null;
let routing_method = 'no_match';

for (const id of data.source_ids) {
  if (BRAND_MAP[id]) {
    brand_id = BRAND_MAP[id];
    routing_method = 'id_match:' + id;
    break;
  }
}

return { ...data, brand_id, routing_method, timestamp: new Date().toISOString() };
